from __future__ import annotations
from dataclasses import dataclass, field
from typing import Any


# ---------- Memory layer mapping ----------

@dataclass
class InContextMemory:
    """
    Working memory — everything currently in the LLM context window.
    Bounded by the model's token limit (e.g. 200 k tokens for claude-sonnet-4-6).
    """
    system_prompt: str = ""
    messages: list[dict] = field(default_factory=list)
    token_budget: int = 200_000

    def add(self, role: str, content: str) -> None:
        self.messages.append({"role": role, "content": content})

    @property
    def approx_tokens(self) -> int:
        # Rough estimate: 1 token ≈ 4 chars
        total = len(self.system_prompt)
        for m in self.messages:
            total += len(m.get("content", ""))
        return total // 4

    def fits(self, new_content: str) -> bool:
        return self.approx_tokens + len(new_content) // 4 < self.token_budget


@dataclass
class EpisodicMemory:
    """
    Long-term episodic store — records of past events.
    Retrieved by semantic similarity and injected into context.
    """
    entries: list[dict] = field(default_factory=list)

    def store(self, content: str, metadata: dict | None = None) -> None:
        self.entries.append({"content": content, "meta": metadata or {}})

    def retrieve(self, query: str, k: int = 3) -> list[str]:
        """Simplified: return last k entries. Real impl uses vector similarity."""
        recent = self.entries[-k:]
        return [e["content"] for e in recent]


@dataclass
class SemanticMemory:
    """Long-term semantic store — facts independent of when they were learned."""
    facts: dict[str, str] = field(default_factory=dict)

    def add(self, key: str, value: str) -> None:
        self.facts[key] = value

    def lookup(self, key: str) -> str | None:
        return self.facts.get(key)


# In ACT-R terms:
# InContextMemory  ≈ Working Memory (goal + imaginal buffers)
# EpisodicMemory   ≈ Episodic Long-Term Memory
# SemanticMemory   ≈ Semantic Long-Term Memory
# LLM weights      ≈ Procedural + Declarative Memory (compressed)

import anthropic
import json


client = anthropic.Anthropic()

# Tools the agent can call (motor module analogue)
TOOLS = [
    {
        "name": "web_search",
        "description": "Search the web for current information.",
        "input_schema": {
            "type": "object",
            "properties": {"query": {"type": "string"}},
            "required": ["query"],
        },
    },
    {
        "name": "calculator",
        "description": "Evaluate a Python arithmetic expression.",
        "input_schema": {
            "type": "object",
            "properties": {"expression": {"type": "string"}},
            "required": ["expression"],
        },
    },
]


def execute_tool(name: str, inputs: dict) -> str:
    """Stub — in production this calls real APIs."""
    if name == "calculator":
        try:
            return str(eval(inputs["expression"], {"__builtins__": {}}))
        except Exception as e:
            return f"Error: {e}"
    if name == "web_search":
        return f"[Stub] Results for: {inputs['query']}"
    return "Unknown tool"


def react_agent(task: str, max_steps: int = 5) -> str:
    """
    ReAct loop: Reason → Act → Observe, repeat.
    The LLM's context window is the working memory;
    each tool call + result extends it.
    """
    messages = [{"role": "user", "content": task}]

    for step in range(max_steps):
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=1024,
            tools=TOOLS,
            messages=messages,
        )

        # Append assistant turn
        messages.append({"role": "assistant", "content": response.content})

        # If no tool call → final answer
        if response.stop_reason == "end_turn":
            for block in response.content:
                if hasattr(block, "text"):
                    return block.text
            break

        # Execute tool calls and feed results back
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                result = execute_tool(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result,
                })

        if tool_results:
            messages.append({"role": "user", "content": tool_results})

    return "Max steps reached"


